<script setup lang="ts">/* CinematicNode — 电影感组合器 */import { computed } from 'vue';import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean}>();const cs=useCanvasStore();const d=computed(()=>p.data||{})
function patch(k:string,v:string){cs.updateNodeData(p.id,{[k]:v})}
function run(){const parts=[d.value.style,d.value.shot,d.value.lighting,d.value.color,d.value.texture].filter(Boolean);cs.updateNodeData(p.id,{outputPrompt:parts.join('，'),status:'success',progress:100})}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#ec4899':'var(--border)'}"><div class="xh"><div class="xi" style="background:rgba(236,72,153,.18);color:#f9a8d4"><span class="mso" style="font-size:13px">theaters</span></div><div class="xl">电影感</div><button class="xr" @pointerdown.stop @click.stop="run"><span class="mso">auto_awesome</span></button></div><div class="xb" @mousedown.stop><select class="xi2" @change="patch('style',($event.target as any).value)"><option value="">风格</option><option value="cinematic">电影感</option><option value="anime">动漫</option><option value="realistic">写实</option></select><select class="xi2" @change="patch('shot',($event.target as any).value)"><option value="">镜头</option><option value="close-up">特写</option><option value="medium">中景</option><option value="wide">广角</option></select><select class="xi2" @change="patch('lighting',($event.target as any).value)"><option value="">光影</option><option value="natural">自然光</option><option value="dramatic">戏剧光</option><option value="soft">柔光</option></select><div v-if="data.outputPrompt" class="xo">{{data.outputPrompt}}</div></div><Handle type="source" :position="Position.Right" :style="{background:'#ec4899',width:10,height:10,border:'none'}"/></div></template>
<style scoped>.x{width:280px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:#ec4899}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xr{width:26px;height:26px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink2);cursor:pointer;display:flex;align-items:center;justify-content:center}.xb{padding:10px;display:flex;flex-direction:column;gap:6px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.xo{max-height:100px;overflow:auto;white-space:pre-wrap;padding:6px;border-radius:4px;background:var(--surface);font-size:11px;word-break:break-all}</style>
